  const [strategicMap, setStrategicMap] = useState<StrategicMapItem[]>([]);
  const [catalog, setCatalog] = useState<SolutionItem[]>([]);
  const [proposalHistory, setProposalHistory] = useState<ProposalRecord[]>([]);
  const [metadata, setMetadata] = useState<ProposalMetadata>({
    clientName: '',
    industry: '',
    website: '',
    instagram: '',
    meetingNotesPains: '',
    meetingNotesDesires: '',
    observations: '',
    date: new Date().toLocaleDateString('pt-BR'),
    consultant: 'Estrategista PhantLab',
    headline: 'PROPOSTA DE MOVIMENTO ESTRATÉGICO'
  });

  const [isGeneratingAI, setIsGeneratingAI] = useState(false);
  const [isImprovingText, setIsImprovingText] = useState(false);
  const [exportStatus, setExportStatus] = useState<'idle' | 'saving' | 'ready' | 'error'>('idle');
  const [activeTab, setActiveTab] = useState<'info' | 'solutions' | 'mapping' | 'history'>('info');
  const [zoom, setZoom] = useState(0.6);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [validationError, setValidationError] = useState<string | null>(null);
  const previewRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem('phant_current_proposal');
    if (saved) setProposalItems(JSON.parse(saved));
    SupabaseService.fetchSolutions().then(data => setCatalog(data || []));
    loadHistory();
  }, []);

  const loadHistory = async () => {
    const history = await SupabaseService.fetchProposalsHistory();
    setProposalHistory(history || []);
  };

  const total = proposalItems.reduce((acc, curr) => acc + curr.totalPrice, 0);
  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  const handleGenerateAI = async () => {
    if (!metadata.clientName) {
      setValidationError("O nome do cliente é obrigatório para análise.");
      setActiveTab('info');
      setTimeout(() => setValidationError(null), 3000);
      return;
    }
    setIsGeneratingAI(true);
    try {
      const mapping = await generateStrategicMapping(metadata);
      setStrategicMap(mapping || []);
      setActiveTab('mapping');
    } catch (err) {
      console.error(err);
      setValidationError("A pesquisa da IA falhou.");
    } finally {
      setIsGeneratingAI(false);
    }
  };

  const handleImproveText = async () => {
    if (!metadata.observations?.trim() || isImprovingText) return;
    setIsImprovingText(true);
    try {
      const improved = await improveObservationText(metadata.observations);
      setMetadata(prev => ({ ...prev, observations: improved }));
    } finally {
      setIsImprovingText(false);
    }
  };

  const handleAddSolution = (sol: SolutionItem) => {
    const newItem: ProposalItem = {
      instanceId: `manual-${Date.now()}`,
      solutionId: sol.id,
      name: sol.solucao,
      basePrice: sol.valor_base_num,
      selectedOptions: [],
      totalPrice: sol.valor_base_num,
      duration: sol.duracao,
      description: sol.descricao,
      deliverables: sol.entregaveis || []
    };
    setProposalItems(prev => [...prev, newItem]);
  };

  const removeSolution = (id: string) => {
    setProposalItems(prev => prev.filter(p => p.instanceId !== id));
  };

  const handleExport = async () => {
    if (!metadata.clientName) {
      setValidationError("Defina o nome do cliente antes de salvar.");
      setActiveTab('info');
      setTimeout(() => setValidationError(null), 3000);
      return;
    }
    if (exportStatus !== 'idle') return;

    setExportStatus('saving');
    try {
      const res = await SupabaseService.saveProposal(
        metadata.clientName,
        metadata.industry || "N/A",
        total,
        metadata.consultant,
        proposalItems,
        metadata
      );

      if (!res.success) {
        throw new Error(res.message);
      }

      await loadHistory();
      setExportStatus('ready');

      setTimeout(() => {
        window.print();
        setExportStatus('idle');
      }, 1500);

    } catch (err: any) {
      console.error("Erro na exportação:", err);
      setExportStatus('error');
      setTimeout(() => setExportStatus('idle'), 4000);
    }
  };

  const loadFromHistory = (record: ProposalRecord) => {
    if (!record) return;
    setProposalItems(Array.isArray(record.items) ? record.items : []);
    setMetadata({
      clientName: record.client_name || '',
      industry: record.industry || '',
      website: record.metadata?.website || '',
      instagram: record.metadata?.instagram || '',
      meetingNotesPains: record.metadata?.meetingNotesPains || '',
      meetingNotesDesires: record.metadata?.meetingNotesDesires || '',
      observations: record.metadata?.observations || '',
      date: record.metadata?.date || new Date(record.created_at).toLocaleDateString('pt-BR'),
      consultant: record.consultant || 'Estrategista PhantLab',
      headline: record.metadata?.headline || 'PROPOSTA DE MOVIMENTO ESTRATÉGICO'
    });
    setActiveTab('solutions');
    const scrollArea = document.querySelector('.proposal-preview-area');
    if (scrollArea) scrollArea.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const adjustZoom = (delta: number) => setZoom(prev => Math.min(Math.max(prev + delta, 0.2), 2));
  const fitToScreen = () => setZoom(0.6);
  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      previewRef.current?.requestFullscreen();
      setIsFullscreen(true);
    } else {
      document.exitFullscreen();
      setIsFullscreen(false);
    }
  };

  const handlePrint = () => window.print();

  return (
    <div className={`flex flex-col lg:flex-row gap-8 animate-in fade-in duration-700 ${isFullscreen ? 'fixed inset-0 z-[100] bg-black p-0 overflow-hidden' : ''}`}>

      {!isFullscreen && (
        <div className="w-full lg:w-[450px] space-y-8 no-print shrink-0">
          <header className="space-y-2">
            <h2 className="text-4xl font-black text-gray-900 tracking-tighter">PDF Builder.</h2>
            <p className="text-gray-400 text-sm font-medium">Configure a proposta executiva abaixo.</p>
          </header>

          <div className="bg-white rounded-[40px] border border-gray-100 shadow-xl overflow-hidden flex flex-col h-[750px] relative">
            {validationError && (
              <div className="absolute top-16 left-0 right-0 z-50 px-8 py-3 bg-red-600 text-white text-[10px] font-black uppercase tracking-widest text-center animate-in slide-in-from-top-full duration-300">
                {validationError}
              </div>
            )}

            <nav className="flex p-4 gap-2 bg-gray-50 border-b border-gray-100">
              {(['info', 'solutions', 'mapping', 'history'] as const).map(t => (
                <button 
                  key={t}
                  onClick={() => setActiveTab(t)}
                  className={`flex-1 py-3 rounded-2xl text-[9px] font-black uppercase tracking-widest transition-all ${activeTab === t ? 'bg-black text-white shadow-lg' : 'text-gray-400 hover:text-black'}`}
                >
                  {t === 'info' ? 'Pesquisa' : t === 'solutions' ? 'Escopo' : t === 'mapping' ? 'Mapa IA' : 'Histórico'}
                </button>
              ))}
            </nav>

            <div className="flex-1 overflow-y-auto p-8 space-y-8 custom-scrollbar">
              {activeTab === 'info' && (
                <div className="space-y-6 animate-in slide-in-from-left-4 duration-300">
                  <div className="space-y-2">
                    <label className={`text-[10px] font-black uppercase tracking-widest ml-2 transition-colors ${validationError ? 'text-red-500' : 'text-gray-300'}`}>Cliente</label>
                    <input 
                      value={metadata.clientName}
                      onChange={e => {
                        setMetadata({...metadata, clientName: e.target.value.toUpperCase()});
                        if (validationError) setValidationError(null);
                      }}
                      className={`w-full bg-gray-50 border p-4 rounded-2xl font-black text-sm focus:bg-white outline-none transition-all ${validationError ? 'border-red-500 ring-2 ring-red-100' : 'border-transparent focus:border-brand'}`}
                      placeholder="NOME DA EMPRESA"
                    />
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-gray-300 uppercase tracking-widest ml-2">Website</label>
                      <input 
                        value={metadata.website}
                        onChange={e => setMetadata({...metadata, website: e.target.value})}
                        className="w-full bg-gray-50 p-4 rounded-2xl font-bold text-xs outline-none"
                        placeholder="site.com.br"
                      />
                    </div>
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-gray-300 uppercase tracking-widest ml-2">Instagram</label>
                      <input 
                        value={metadata.instagram}
                        onChange={e => setMetadata({...metadata, instagram: e.target.value})}
                        className="w-full bg-gray-50 p-4 rounded-2xl font-bold text-xs outline-none"
                        placeholder="@perfil"
                      />
                    </div>
                  </div>

                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-amber-500/50 uppercase tracking-widest ml-2">Dores Percebidas (Call)</label>
                    <textarea 
                      value={metadata.meetingNotesPains}
                      onChange={e => setMetadata({...metadata, meetingNotesPains: e.target.value})}
                      className="w-full bg-gray-50 p-4 rounded-2xl font-medium text-xs min-h-[80px] outline-none"
                      placeholder="Quais problemas o cliente relatou?"
                    />
                  </div>

                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-emerald-500/50 uppercase tracking-widest ml-2">Desejos Percebidos</label>
                    <textarea 
                      value={metadata.meetingNotesDesires}
                      onChange={e => setMetadata({...metadata, meetingNotesDesires: e.target.value})}
                      className="w-full bg-gray-50 p-4 rounded-2xl font-medium text-xs min-h-[80px] outline-none"
                      placeholder="Qual o objetivo de escala?"
                    />
                  </div>

                  <button 
                    onClick={handleGenerateAI}
                    disabled={isGeneratingAI}
                    className="w-full py-5 bg-brand text-white rounded-[30px] font-black text-[10px] uppercase tracking-widest hover:bg-black transition-all shadow-xl disabled:opacity-50"
                  >
                    {isGeneratingAI ? 'PESQUISANDO WEB & ADS...' : '✨ Analisar e Gerar Estratégia'}
                  </button>
                </div>
              )}

              {activeTab === 'solutions' && (
                <div className="space-y-6 animate-in slide-in-from-left-4 duration-300">
                  <h4 className="text-[10px] font-black text-gray-300 uppercase tracking-widest">Escopo Selecionado</h4>
                  {proposalItems.map(item => (
                      <div key={item.instanceId} className="p-4 bg-gray-50 rounded-2xl flex justify-between items-center group">
                        <div className="overflow-hidden">
                          <p className="font-black text-[11px] truncate">{item.name}</p>
                          <p className="text-[9px] text-brand font-bold uppercase">{formatCurrency(item.totalPrice)}</p>
                        </div>
                        <button onClick={() => removeSolution(item.instanceId)} className="text-gray-300 hover:text-red-500 transition-all">
                          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12"/></svg>
                        </button>
                      </div>
                    ))}
                    <div className="pt-6 border-t border-gray-100 space-y-4">
                      <h4 className="text-[10px] font-black text-gray-300 uppercase tracking-widest">Catálogo Disponível</h4>
                      {catalog.map(sol => (
                        <button 
                          key={sol.id}
                          onClick={() => handleAddSolution(sol)}
                          className="w-full text-left p-4 bg-white border border-gray-100 rounded-2xl hover:border-brand transition-all flex justify-between items-center group"
                        >
                          <span className="font-bold text-[11px] text-gray-600 group-hover:text-black">{sol.solucao}</span>
                          <span className="text-[8px] font-black text-brand">+ ADD</span>
                        </button>
                      ))}
                    </div>
                </div>
              )}

              {activeTab === 'mapping' && (
                <div className="space-y-6 animate-in slide-in-from-left-4 duration-300">
                  <h4 className="text-[10px] font-black text-gray-300 uppercase tracking-widest">Ajuste o Mapeamento</h4>
                  {(strategicMap || []).map((m, i) => (
                    <div key={i} className="space-y-4 p-6 bg-gray-50 rounded-[24px] border border-gray-100">
                        <div className="space-y-1">
                          <label className="text-[8px] font-black text-red-400 uppercase tracking-widest">Estado Atual</label>
                          <textarea 
                            value={m.current}
                            onChange={e => {
                              const next = [...strategicMap];
                              next[i].current = e.target.value;
                              setStrategicMap(next);
                            }}
                            className="w-full bg-transparent border-none p-0 text-xs font-medium text-gray-500 min-h-[50px] resize-none focus:ring-0"
                          />
                        </div>
                        <div className="w-full h-px bg-gray-200"></div>
                        <div className="space-y-1">
                          <label className="text-[8px] font-black text-emerald-500 uppercase tracking-widest">Estado Desejado</label>
                          <textarea 
                            value={m.desired}
                            onChange={e => {
                              const next = [...strategicMap];
                              next[i].desired = e.target.value;
                              setStrategicMap(next);
                            }}
                            className="w-full bg-transparent border-none p-0 text-xs font-black text-gray-900 min-h-[50px] resize-none focus:ring-0"
                          />
                        </div>
                    </div>
                  ))}
                </div>
              )}

              {activeTab === 'history' && (
                <div className="space-y-4 animate-in slide-in-from-left-4 duration-300">
                  <div className="flex justify-between items-center">
                    <h4 className="text-[10px] font-black text-gray-300 uppercase tracking-widest">Propostas Recentes</h4>
                    <button onClick={loadHistory} className="text-[8px] font-black text-brand uppercase">Atualizar</button>
                  </div>
                  {proposalHistory.length > 0 ? proposalHistory.map(record => (
                    <div key={record.id} className="p-5 bg-gray-50 rounded-[24px] border border-gray-100 space-y-3 group hover:border-brand transition-all cursor-pointer" onClick={() => loadFromHistory(record)}>
                       <div className="flex justify-between items-start">
                          <div>
                             <p className="font-black text-[12px] text-gray-900 leading-none">{record.client_name}</p>
                             <p className="text-[8px] font-bold text-gray-400 uppercase tracking-widest mt-1">
                                {new Date(record.created_at).toLocaleDateString('pt-BR')}
                             </p>
                          </div>
                          <span className="text-[10px] font-black text-brand">{formatCurrency(record.total_value)}</span>
                       </div>
                       <div className="flex justify-between items-center pt-2">
                          <span className="text-[8px] font-black text-gray-300 uppercase">Por: {record.consultant?.split(' ')[0] || '---'}</span>
                          <span className="text-[8px] font-black text-brand uppercase group-hover:underline">Carregar Scopo</span>
                       </div>
                    </div>
                  )) : (
                    <div className="py-20 text-center opacity-20 font-black uppercase text-[10px] tracking-widest">Sem histórico.</div>
                  )}
                </div>
              )}
            </div>

            <div className="p-8 bg-black text-white space-y-6">
              <div className="space-y-3">
                <div className="flex justify-between items-center">
                  <label className="text-[9px] font-black text-white/40 uppercase tracking-widest">Observações gerais</label>
                  <button 
                    onClick={handleImproveText}
                    disabled={isImprovingText || !metadata.observations}
                    className="text-[8px] font-black text-brand uppercase tracking-widest hover:text-white transition-colors flex items-center gap-1"
                  >
                    {isImprovingText ? '...' : '✨ Refinar com IA'}
                  </button>
                </div>
                <textarea 
                  value={metadata.observations}
                  onChange={e => setMetadata({...metadata, observations: e.target.value})}
                  className="w-full bg-white/5 border border-white/10 p-4 rounded-xl text-[10px] font-medium text-white/80 min-h-[80px] outline-none focus:bg-white/10 transition-all"
                  placeholder="Acordos extras ou condições de pagamento..."
                />
              </div>

              <div className="flex justify-between items-end">
                  <span className="text-[10px] font-black text-white/30 uppercase tracking-widest">Total Investimento</span>
                  <span className="text-3xl font-black tracking-tighter">{formatCurrency(total)}</span>
              </div>
              <button 
                onClick={handleExport} 
                disabled={exportStatus !== 'idle'}
                className={`w-full py-5 rounded-[24px] font-black text-[11px] uppercase tracking-[0.2em] shadow-xl hover:scale-105 transition-all disabled:opacity-50 flex items-center justify-center gap-3 ${
                  exportStatus === 'ready' ? 'bg-emerald-500 text-white' : 
                  exportStatus === 'error' ? 'bg-red-500 text-white' : 
                  'bg-brand text-white'
                }`}
              >
                {exportStatus === 'saving' && <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></span>}
                {exportStatus === 'saving' ? 'SALVANDO NO SUPABASE...' : 
                 exportStatus === 'ready' ? 'SUCESSO! ABRINDO PDF...' : 
                 exportStatus === 'error' ? 'ERRO AO SALVAR. TENTE NOVAMENTE' :
                 'SALVAR E EXPORTAR PDF'}
              </button>
            </div>
          </div>

          <div className="bg-white rounded-[32px] border border-gray-100 p-8 shadow-sm no-print">
            <div className="flex justify-between items-center mb-6">
               <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em]">Recém Gerados</h4>
               <span className="text-[9px] font-bold text-brand uppercase">{proposalHistory.length} total</span>
            </div>
            <div className="space-y-3">
               {proposalHistory.slice(0, 3).map(record => (
                 <button 
                  key={record.id} 
                  onClick={() => loadFromHistory(record)}
                  className="w-full text-left p-4 bg-gray-50 rounded-2xl hover:bg-gray-100 transition-colors flex justify-between items-center group"
                 >
                    <div className="overflow-hidden">
                       <p className="font-bold text-[11px] truncate text-gray-900">{record.client_name}</p>
                       <p className="text-[8px] text-gray-400 font-bold uppercase">{new Date(record.created_at).toLocaleDateString('pt-BR')}</p>
                    </div>
                    <svg className="w-3 h-3 text-gray-300 group-hover:text-brand transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 5l7 7-7 7"/></svg>
                 </button>
               ))}
               <button 
                onClick={() => setActiveTab('history')}
                className="w-full py-3 text-[9px] font-black text-gray-300 uppercase tracking-widest hover:text-brand transition-colors text-center"
               >
                 Ver Histórico Completo
               </button>
            </div>
          </div>
        </div>
      )}

      <div 
        ref={previewRef}
        className={`flex-1 relative flex flex-col items-center bg-[#151515] rounded-[60px] overflow-y-auto custom-scrollbar proposal-preview-area ${isFullscreen ? 'h-full w-full rounded-none' : 'p-12 max-h-[1000px]'}`}
      >
        <div className="sticky top-4 z-[50] no-print bg-white/10 backdrop-blur-xl border border-white/10 rounded-full p-2 flex items-center gap-2 mb-8 shadow-2xl">
          <button onClick={() => adjustZoom(-0.1)} className="w-10 h-10 flex items-center justify-center text-white hover:bg-white/10 rounded-full transition-colors" title="Zoom Out">
             <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M20 12H4" strokeWidth="3" strokeLinecap="round"/></svg>
          </button>
          <span className="text-[10px] font-black text-white/40 uppercase tracking-widest px-2 min-w-[50px] text-center">{Math.round(zoom * 100)}%</span>
          <button onClick={() => adjustZoom(0.1)} className="w-10 h-10 flex items-center justify-center text-white hover:bg-white/10 rounded-full transition-colors" title="Zoom In">
             <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="3" strokeLinecap="round"/></svg>
          </button>
          <div className="w-px h-6 bg-white/10 mx-1"></div>
          <button onClick={fitToScreen} className="px-4 py-2 text-[9px] font-black text-white uppercase tracking-widest hover:bg-white/10 rounded-full transition-colors" title="Fit to Screen">
             Enquadrar
          </button>
          <button onClick={handlePrint} className="px-4 py-2 bg-emerald-500 text-white text-[9px] font-black uppercase tracking-widest rounded-full hover:bg-emerald-600 transition-all flex items-center gap-2 shadow-lg shadow-emerald-500/20">
             <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"/></svg>
             Imprimir PDF
          </button>
          <button onClick={toggleFullscreen} className="w-10 h-10 flex items-center justify-center text-white hover:bg-white/10 rounded-full transition-colors" title="Toggle Fullscreen">
             <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
               {isFullscreen ? (
                 <path d="M4 14h6m0 0v6m0-6L3 21m17-7h-6m0 0v6m0-6l7 7M4 10h6m0 0V4m0 6L3 3m17 7h-6m0 0V4m0 6l7-7" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/>
               ) : (
                 <path d="M15 3h6m0 0v6m0-6L14 10M9 3H3m0 0v6m0-6l7 7M15 21h6m0 0v-6m0 6l-7-7M9 21H3m0 0v-6m0 6l7-7" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/>
               )}
             </svg>
          </button>
        </div>

        <div 
          className="transition-transform duration-300 flex flex-col items-center origin-top"
          style={{ transform: `scale(${zoom})` }}
        >
          <section className="w-[210mm] min-h-[297mm] bg-black text-white p-24 flex flex-col justify-between relative shadow-2xl shrink-0 mb-12 print:shadow-none print:mb-0 animate-in zoom-in-95 duration-500">
            <PhantPattern />
            <div className="relative z-10 flex justify-between items-start">
              <div className="w-16 h-16 bg-white text-black font-black flex items-center justify-center text-4xl">P</div>
              <div className="text-right">
                  <p className="text-[10px] font-black uppercase tracking-[0.4em] text-brand">Estrategista Comercial</p>
                  <p className="font-bold text-sm mt-1">{metadata.consultant}</p>
              </div>
            </div>

            <div className="relative z-10 space-y-12">
              <h1 className="text-8xl font-black tracking-tighter leading-[0.85] uppercase">
                  {metadata.headline?.split(' ').map((word, i) => (
                    <span key={i} className="block">{word}</span>
                  ))}
              </h1>
              <div className="w-32 h-2 bg-brand"></div>
            </div>

            <div className="relative z-10 flex justify-between items-end border-t border-white/20 pt-12">
              <div className="space-y-2">
                  <p className="text-[11px] font-black uppercase tracking-[0.5em] text-white/40">Exclusivo para</p>
                  <p className="text-5xl font-black tracking-tighter">{metadata.clientName || 'CLIENTE'}</p>
              </div>
              <div className="text-right">
                  <p className="text-[11px] font-black uppercase tracking-widest text-white/40">Emissão</p>
                  <p className="font-bold text-lg">{metadata.date}</p>
              </div>
            </div>
          </section>

          <section className="w-[210mm] min-h-[297mm] bg-[#F9F9F9] text-black p-24 flex flex-col justify-between shadow-2xl shrink-0 mb-12 print:shadow-none print:mb-0">
            <div className="flex justify-between items-center border-b-4 border-black pb-10">
                <h2 className="text-4xl font-black tracking-tighter uppercase leading-none">Mapa de<br/>Movimento.</h2>
                <span className="text-[10px] font-black uppercase tracking-widest bg-black text-white px-4 py-1">PHANT AI INSIGHT</span>
            </div>

            <div className="flex-1 py-16 flex flex-col justify-center space-y-1">
