                  <p className="text-[9px] font-black uppercase text-black/40 tracking-widest">Site Oficial</p>
                  <p className="font-bold text-lg">www.{appConfig.companyName.toLowerCase().replace(/\s/g, '')}.com.br</p>
               </div>
            </div>
          </section>
        </div>
      </div>
    </div>
  );
};

export default ProposalBuilder;
